parameters.jsCode:
const crypto = require('crypto');
const text = $input.first().json.candidates[0].content.parts[0].text;
const cleaned = text.replace(/```json|```/g, '').trim();
const d = JSON.parse(cleaned);
const raw = `${d.store_name}|${d.receipt_date}|${d.total_amount}|${d.receipt_number}`;
const hash = crypto.createHash('sha256').update(raw).digest('hex');
return [{ json: { hash, store_name: d.store_name, receipt_date: d.receipt_date, total_amount: d.total_amount, receipt_number: d.receipt_number }}];

const items = $input.all();
const count = items.filter(i => i.json.user_id).length;
return [{ json: { dailyCount: count, shouldStop: count > 5, decision: count > 5 ? 'stop' : 'proceed' }}];

const text = $input.first().json.candidates[0].content.parts[0].text;
const cleaned = text.replace(/```json|```/g, '').trim();
const parsed = JSON.parse(cleaned);
return [{ json: { extractedReceipt: parsed, confidence: parsed.confidence } }];

const ticket = $('Supabase Ticket Trigger').first().json.body.record;
const extracted = $('Parse Receipt').first().json.extractedReceipt;
const submittedAt = new Date(ticket.submitted_at);
const receiptDate = new Date(extracted.receipt_date + 'T' + (extracted.receipt_time || '23:59:59'));

const invalidStoreTypes = [
  'el corte ingles', 'restaurant', 'restaurante', 'farmacia',
  'pharmacy', 'gasolinera', 'gas station', 'bar ', 'cafe ',
  'cafeteria', 'cafè', 'mcdonald', 'burger', 'pizz', 'kebab',
  'panaderia', 'panadería', 'pasteleria', 'pastelería',
  'drogueria', 'droguería', 'brico', 'ferreteria', 'ferretería',
  'zara', 'primark', 'decathlon', 'ikea', 'leroy', 'fnac',
  'mediamarkt', 'worten', 'optica', 'óptica', 'clinica', 'clínica',
  'freshly', 'jr s.l', 'delivery', 'takeaway', 'comida',
  'cocina', 'bistro', 'tapas', 'cerveceria', 'cervecería',
  'heladeria', 'heladería', 'churreria', 'churros', 'sushi',
  'wok', 'thai', 'chinese', 'indian', 'italiano', 'trattoria'
];

const storeName = (extracted.store_name || '').toLowerCase();

if (!storeName || storeName === 'null' || storeName === '')
  return [{ json: { approved: false, reason: 'INCOMPLETE_TICKET',
    message: 'Hola 👋, necesitamos ver el ticket completo y fecha de compra. ¡Gracias!'
  }}];

const isInvalidStoreType = invalidStoreTypes.some(s => storeName.includes(s));
if (isInvalidStoreType)
  return [{ json: { approved: false, reason: 'INVALID_STORE',
    message: 'Hola 👋, solo aceptamos tickets de supermercados. ¡Gracias!'
  }}];

const storeLocation = (extracted.store_location || '').toLowerCase();
const storeCountry = (extracted.store_country || '').toLowerCase();
const currency = (extracted.currency || '').toLowerCase();
const spainKeywords = ['spain', 'españa', 'esp', ', es'];
const isSpain =
  spainKeywords.some(k => storeLocation.includes(k)) ||
  spainKeywords.some(k => storeCountry.includes(k)) ||
  currency === 'eur' || currency === '€';

if (!isSpain)
  return [{ json: { approved: false, reason: 'NOT_SPAIN',
    message: 'Hola 👋, solo aceptamos tickets de supermercados. ¡Gracias!'
  }}];

if (!extracted.receipt_date || extracted.receipt_date === 'null' || extracted.receipt_date === '')
  return [{ json: { approved: false, reason: 'INCOMPLETE_TICKET',
    message: 'Hola 👋, necesitamos ver el ticket completo y fecha de compra. ¡Gracias!'
  }}];

if (!extracted.total_amount || extracted.total_amount === 0)
  return [{ json: { approved: false, reason: 'INCOMPLETE_TICKET',
    message: 'Hola 👋, necesitamos ver el ticket completo y fecha de compra. ¡Gracias!'
  }}];

const diffHours = (submittedAt - receiptDate) / 3600000;

if (diffHours < -2)
  return [{ json: { approved: false, reason: 'FUTURE_DATE',
    message: 'Hola 👋, necesitamos ver el ticket completo y fecha de compra. ¡Gracias!'
  }}];

if (diffHours > 24)
  return [{ json: { approved: false, reason: 'OUTSIDE_24H',
    message: 'Hola 👋, el ticket debe enviarse dentro de las 24h posteriores a la compra. ¡Gracias!'
  }}];

return [{ json: {
  approved: true,
  points: 2,
  flow: 1,
  store_name: extracted.store_name,
  receipt_date: extracted.receipt_date,
  hours_since_purchase: Math.round(diffHours * 10) / 10
}}];

const item = $input.first().json;

// If data comes from Merge Product Data (already structured)
if (item.extractedProduct) {
  return [{ json: { extractedProduct: item.extractedProduct }}];
}

// If data comes directly from Gemini (has candidates)
if (item.candidates && item.candidates[0]) {
  const text = item.candidates[0].content.parts[0].text;
  const cleaned = text.replace(/```json|```/g,'').trim();
  return [{ json: { extractedProduct: JSON.parse(cleaned) }}];
}

// Fallback
return [{ json: { extractedProduct: item }}];

const ticket = $('Supabase Ticket Trigger').first().json.body.record;
const extracted = $('Parse Receipt').first().json.extractedReceipt;
const product = $('Parse Product').first().json.extractedProduct;
const receiptDate = new Date(extracted.receipt_date);
const expiryDate = new Date(product.expiry_date);
const submittedAt = new Date(ticket.submitted_at);

if ((submittedAt - receiptDate) / 3600000 > 24)
  return [{ json: { approved: false, reason: 'OUTSIDE_24H',
    message: 'Hola 👋, el ticket debe enviarse dentro de las 24h posteriores a la compra. ¡Gracias!'
  }}];

const daysToExpiry = (expiryDate - receiptDate) / 86400000;

if (daysToExpiry > 5 || daysToExpiry < 0)
  return [{ json: { approved: false, reason: 'EXPIRY_OUT_OF_RANGE',
    message: 'Hola 👋, los puntos son solo para productos que caducan en <5 días de la compra. ¡Gracias!'
  }}];

function sim(s1, s2) {
  if (!s1 || !s2) return 0;
  const w1 = s1.toLowerCase().split(' ');
  const w2 = s2.toLowerCase().split(' ');
  return w1.filter(w => w2.includes(w)).length / Math.max(w1.length, w2.length);
}

const hasGTIN = product.barcode_gtin && product.barcode_gtin.trim() !== '';
let matchedProduct = 'fresh_produce_no_barcode';

if (hasGTIN) {
  let productNames = [];
  try {
    const offResult = $('GTIN Lookup OpenFoodFacts').first().json;
    if (offResult.status === 1 && offResult.product) {
      productNames.push(offResult.product.product_name);
      productNames.push(offResult.product.brands);
    }
  } catch(e) {}
  productNames.push(product.product_name_visible);
  productNames.push(product.brands);
  productNames = productNames.filter(Boolean);
  const items = extracted.line_items || [];
  const match = items.find(i =>
    productNames.some(n => sim(i.name, n) >= 0.75)
  );
  if (!match)
    return [{ json: { approved: false, reason: 'PRODUCT_NOT_ON_RECEIPT',
      message: 'Hola 👋, hemos revisado tu ticket y no encontramos el producto indicado en él. Por ahora, no podemos validarlo. ¡Gracias igualmente por participar!'
    }}];
  matchedProduct = match.name;
}

const pts = {0:5, 1:4, 2:3, 3:2, 4:1}[Math.round(daysToExpiry)] || 0;
return [{ json: {
  approved: true,
  points: pts,
  flow: 2,
  matched_product: matchedProduct,
  days_to_expiry: Math.round(daysToExpiry)
}}];

