const barcodeText = $('Extract Barcode').first().json.candidates[0].content.parts[0].text;
const expiryText = $('Extract Expiry').first().json.candidates[0].content.parts[0].text;

const b = JSON.parse(barcodeText.replace(/```json|```/g,'').trim());
const e = JSON.parse(expiryText.replace(/```json|```/g,'').trim());

// If no expiry found, use today + 1 day as default for fresh produce
const expiryDate = e.expiry_date || new Date(Date.now() + 86400000).toISOString().split('T')[0];

return [{ json: { 
  extractedProduct: {
    barcode_gtin: b.barcode_gtin,
    barcode_confidence: b.barcode_confidence || 0,
    expiry_date: expiryDate,
    expiry_confidence: e.expiry_confidence || 50,
    tampering_detected: e.tampering_detected || false
  }
}}];

const record = $('Supabase Ticket Trigger').first().json.body.record;
const submissionType = record.submission_type;
const receiptUrl = record.receipt_url;
const barcodeUrl = record.barcode_url;
const expiryUrl = record.expiry_url;

// Flow 1 - only receipt required
if (submissionType === 1) {
  if (!receiptUrl || receiptUrl === '' || receiptUrl === null) {
    return [{ json: {
      imagesValid: false,
      reason: 'MISSING_RECEIPT',
      message: 'Hola 👋, necesitamos ver el ticket completo y fecha de compra. ¡Gracias!'
    }}];
  }
}

// Flow 2 - receipt + barcode + expiry required
if (submissionType === 2) {
  if (!receiptUrl || receiptUrl === '' || receiptUrl === null) {
    return [{ json: {
      imagesValid: false,
      reason: 'MISSING_RECEIPT',
      message: 'Hola 👋, necesitamos ver el ticket completo y fecha de compra. ¡Gracias!'
    }}];
  }
  if (!barcodeUrl || barcodeUrl === '' || barcodeUrl === null) {
    return [{ json: {
      imagesValid: false,
      reason: 'MISSING_BARCODE',
      message: 'Hola 👋, la fecha de caducidad y código de barras deben ser bien visibles. ¡Gracias!'
    }}];
  }
  if (!expiryUrl || expiryUrl === '' || expiryUrl === null) {
    return [{ json: {
      imagesValid: false,
      reason: 'MISSING_EXPIRY',
      message: 'Hola 👋, además del código de barras, necesitamos foto clara de la fecha de caducidad corta. ¡Gracias!'
    }}];
  }
}

// All required images present
return [{ json: { imagesValid: true, submissionType }}];

